CREATE TABLE packages (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL,price DECIMAL(10,2) NOT NULL,duration_days INT NOT NULL,description TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,email VARCHAR(190) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,role ENUM('user','admin') NOT NULL DEFAULT 'user',jellyfin_user_id VARCHAR(64) NULL,package_id INT NULL,expires_at DATETIME NULL,status ENUM('pending_payment','active','expired','grace','suspended','cancelled') NOT NULL DEFAULT 'pending_payment',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY (package_id) REFERENCES packages(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE settings (id INT PRIMARY KEY,site_logo VARCHAR(255) NULL,site_name VARCHAR(150) NOT NULL);
INSERT INTO settings(id,site_logo,site_name) VALUES (1,'','StreamBox') ON DUPLICATE KEY UPDATE site_name=VALUES(site_name);
CREATE TABLE job_queue (id BIGINT AUTO_INCREMENT PRIMARY KEY,type VARCHAR(50) NOT NULL,payload JSON NOT NULL,status ENUM('pending','success','failed') NOT NULL DEFAULT 'pending',retry_count INT NOT NULL DEFAULT 0,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE audit_logs (id BIGINT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,action VARCHAR(100) NOT NULL,details JSON NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(user_id),FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB;
